sql:
SELECT step_name, action_type, target_audience
FROM journey_steps
WHERE action_type = 'email' AND target_audience = 'All new customers';

SELECT version_number, COUNT(*) as total_versions
FROM journey_versions
GROUP BY version_number;

SELECT COUNT(step_id) AS total_steps
FROM journey_steps
WHERE version_id = '0';

SELECT version_id, version_number, is_active
FROM journey_versions
WHERE journey_id = '0';

SELECT metric_name, metric_value
FROM journey_performance
WHERE metric_value > 0.5;

SELECT journey_name
FROM journeys
WHERE journey_id = '1';

SELECT AVG(metric_value) AS average_conversion_rate
FROM journey_performance
WHERE metric_name = 'Conversion Rate';

SELECT version_id, AVG(metric_value) AS average_metric_value
FROM journey_performance
GROUP BY version_id;

SELECT owner_id, COUNT(DISTINCT journey_id) AS total_journeys_created
FROM journeys
GROUP BY owner_id;

SELECT MAX(duration) AS max_step_duration
FROM journey_steps
WHERE version_id = '0';

SELECT journey_name 
FROM journeys 
ORDER BY journey_name;

SELECT status, journey_name, COUNT(*) as journey_count
FROM journeys
GROUP BY status, journey_name;
